import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';
import { HttpClientModule } from '@angular/common/http';
import { FormsModule } from '@angular/forms'; // Obligatoire pour le chat [(ngModel)] !

import { AppComponent } from './app.component';
// 1. On importe le bon nom de classe : DashboardComponent
import { DashboardComponent } from './components/dashboard/dashboard.component';

@NgModule({
  declarations: [
    AppComponent,
    DashboardComponent // 2. On déclare DashboardComponent ici
  ],
  imports: [
    BrowserModule,
    HttpClientModule,
    FormsModule // Ajouté ici pour que ta zone de saisie de texte fonctionne
  ],
  providers: [],
  bootstrap: [AppComponent]
})
export class AppModule { }
